import React, { useState, useEffect } from 'react';
import { Link, useLocation } from 'react-router-dom';

const Navbar = () => {
  const [isScrolled, setIsScrolled] = useState(false);
  const location = useLocation();

  useEffect(() => {
    const handleScroll = () => {
      if (window.scrollY > 50) {
        setIsScrolled(true);
      } else {
        setIsScrolled(false);
      }
    };

    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  return (
    <nav className={`fixed w-full z-50 transition-all duration-300 ${isScrolled ? 'glass-nav scrolled py-3' : 'glass-nav py-5'}`}>
      <div className="container mx-auto px-6 md:px-12 flex justify-between items-center">
        <Link to="/" className="flex items-center gap-2">
          <span className="text-3xl font-bold bg-clip-text text-transparent bg-gradient-to-r from-stream-red to-pink-600">
            RaulFlix
          </span>
        </Link>

        <div className="hidden md:flex items-center space-x-8">
          <Link to="/" className={`text-sm font-medium transition-colors hover:text-white ${location.pathname === '/' ? 'text-white' : 'text-gray-300'}`}>Inicio</Link>
          <Link to="/channels" className={`text-sm font-medium transition-colors hover:text-white ${location.pathname === '/channels' ? 'text-white' : 'text-gray-300'}`}>TV en Vivo</Link>
          <Link to="/admin" className={`text-sm font-medium transition-colors hover:text-white ${location.pathname.startsWith('/admin') ? 'text-white' : 'text-gray-300'}`}>Admin</Link>
        </div>

        <div className="flex items-center space-x-4">
          <button className="text-gray-300 hover:text-white transition-colors">
            <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" />
            </svg>
          </button>
          <div className="w-9 h-9 rounded-full bg-gradient-to-tr from-stream-red to-purple-500 border-2 border-white/20 cursor-pointer overflow-hidden flex items-center justify-center">
            <span className="text-sm font-bold text-white">R</span>
          </div>
        </div>
      </div>
    </nav>
  );
};

export default Navbar;
